  ksante: { diff: "TRICKY", tone: "#ff8b3d", tldr: "He\u2019s tanky \u2014 barrel-poke his early, Q-cleanse.", breakdown: "K\u2019Sante is durable. Barrel-poke his weak early, Q-cleanse his slows, and avoid his R form.", dos: ["Barrel-poke his weak early", "Q-cleanse his slows", "Avoid his R form low"], donts: ["Get walled by his Q", "Fight his R form", "Trade in his W tank-up"], key: { slot: "R", name: "All Out", cd: "90s", note: "His duelist mode. Poke when it\u2019s down.", winT: "ALL OUT DOWN", winS: "Barrel-Q + R him." }, hold: "Hold barrels at range \u2014 detonate to poke his weak early; Q-cleanse his slows and avoid his R duel.", tip: "Barrel-poke his weak early, Q-cleanse his slows, and avoid his R form.", win: "Barrel-poke his early and out-scale." },
  malphite: { diff: "TRICKY", tone: "#ff8b3d", tldr: "He stacks armor \u2014 build crit anyway, barrel-poke.", breakdown: "Malphite stacks armor and his R is un-dodgeable. Barrel-poke from range, build Lord Dom\u2019s, and dodge his R.", dos: ["Barrel-poke from range", "Build armor-pen crit", "Dodge his R engage"], donts: ["Auto-trade his passive", "Eat his R knockup", "Fight when his R is up"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "Un-dodgeable burst. Respect it.", winT: "ULT DOWN", winS: "Barrel-Q + R him." }, hold: "Hold barrels at range \u2014 detonate to poke his armor down; build armor-pen and dodge his R.", tip: "He stacks armor \u2014 barrel-poke from range, build armor-pen crit, and dodge his R engage.", win: "Barrel-poke him and build pen." },
  maokai: { diff: "EVEN", tone: "#e8b84b", tldr: "Barrel-poke \u2014 build MR, Q-cleanse his root.", breakdown: "Build MR, barrel-poke from range, and Q-cleanse his W root.", dos: ["Build MR", "Barrel-poke from range", "Q-cleanse his root"], donts: ["Get rooted into his combo", "Fight in saplings", "Eat his R knockback"], key: { slot: "W", name: "Twisted Advance (Root)", cd: "11s", note: "His lock-on root. Cleanse it with Q.", winT: "ROOT DOWN", winS: "Barrel-Q + R him." }, hold: "Hold Q to cleanse his W root \u2014 it breaks the lock-on, then barrel-poke from range.", tip: "Build MR, barrel-poke from range, and Q-cleanse his W root \u2014 out-scale his tank kit.", win: "Cleanse his root and barrel-poke him." },
