  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — barrel his approach and cleanse the Heroic Swing setup.","breakdown":"Akshan plays around Heroic Swing. Triple-barrel chains zone the wave, Q cashes gold, oranges eat his Heroic Swing — and your R prints cross-map wins. Doran’s Shield blunts the poke war.","dos":["Zone with barrels on his path","Q-poke gold off his step-ups","W-cleanse his Heroic Swing setup"],"donts":["Place barrels he can pop free","Hold W too long","Fight with no barrels banked"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Barrel chain + Q cash-out."},"win":"Barrel his approach and cleanse the Heroic Swing setup."},
